  `healthLevel` int NOT NULL,
  `amountOfServings` int NOT NULL,
  `userId` int NOT NULL,
  `sugarRestriction` varchar(45) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
  `lactoseRestrictions` varchar(45) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
